INSERT INTO plugin_catalog (slug, name, description, version, category, tool_manifest, source_repo, source, verified) VALUES ('lucid-hype', 'Lucid Hype', 'Growth hacking: social promotion, campaign automation, engagement tracking', '0.1.0', 'marketing', '[{"name":"hype_create_campaign","description":"Create a new marketing campaign with goals, target platforms, and scheduling. Campaigns group posts and track performance.","parameters":{"type":"object","properties":{"name":{"type":"string","description":"Campaign name"},"description":{"type":"string","description":"Campaign description"},"platforms":{"type":"array","items":{"type":"string","enum":["twitter","linkedin","reddit","tiktok","youtube","instagram","discord","telegram","hackernews","producthunt"]},"description":"Target platforms"},"goals":{"type":"array","items":{"type":"string"},"description":"Campaign goals (e.g., \"increase followers\", \"drive traffic\")"},"status":{"type":"string","enum":["draft","active","paused","completed"],"description":"Initial status (default: draft)"},"start_date":{"type":"string","description":"Start date (ISO)"},"end_date":{"type":"string","description":"End date (ISO)"}},"required":["name","platforms"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"hype_track_post","description":"Track a social media post by recording its URL, platform, content, and initial metrics.","parameters":{"type":"object","properties":{"platform":{"type":"string","enum":["twitter","linkedin","reddit","tiktok","youtube","instagram","discord","telegram","hackernews","producthunt"],"description":"Social media platform"},"url":{"type":"string","description":"Post URL"},"title":{"type":"string","description":"Post title"},"body":{"type":"string","description":"Post body/content"},"content_type":{"type":"string","enum":["post","thread","video","article","story","reel","newsletter"],"description":"Content type (default: post)"},"campaign_id":{"type":"string","description":"Campaign ID to associate"},"impressions":{"type":"number","description":"Current impressions"},"likes":{"type":"number","description":"Current likes"},"shares":{"type":"number","description":"Current shares/retweets"},"comments":{"type":"number","description":"Current comments"},"clicks":{"type":"number","description":"Current clicks"}},"required":["platform"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"hype_get_virality_score","description":"Calculate a virality score (0-100) for content based on engagement velocity, share ratio, comment depth, and amplification.","parameters":{"type":"object","properties":{"impressions":{"type":"number","description":"Total impressions"},"likes":{"type":"number","description":"Total likes"},"shares":{"type":"number","description":"Total shares/retweets"},"comments":{"type":"number","description":"Total comments"},"clicks":{"type":"number","description":"Total clicks"},"hours_live":{"type":"number","description":"Hours since post was published"},"reply_depth_avg":{"type":"number","description":"Average reply thread depth"}},"required":["impressions","likes","shares","comments","hours_live"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"hype_analyze_engagement","description":"Analyze engagement patterns for a set of posts. Returns best posting times, audience segments, sentiment analysis, and top content types.","parameters":{"type":"object","properties":{"posts":{"type":"array","items":{"type":"object","properties":{"platform":{"type":"string","enum":["twitter","linkedin","reddit","tiktok","youtube","instagram","discord","telegram","hackernews","producthunt"]},"contentType":{"type":"string"},"impressions":{"type":"number"},"likes":{"type":"number"},"shares":{"type":"number"},"comments":{"type":"number"},"clicks":{"type":"number"},"postedAt":{"type":"string"}},"required":["platform","impressions","likes","shares","comments","postedAt"],"additionalProperties":false},"description":"Array of post data objects with metrics"},"platform":{"type":"string","enum":["twitter","linkedin","reddit","tiktok","youtube","instagram","discord","telegram","hackernews","producthunt"],"description":"Filter by platform"}},"required":["posts"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"hype_optimize_content","description":"Analyze content and provide optimization suggestions for a specific platform. Scores length, hashtags, readability, CTA, and more.","parameters":{"type":"object","properties":{"text":{"type":"string","description":"Content text to optimize"},"platform":{"type":"string","enum":["twitter","linkedin","reddit","tiktok","youtube","instagram","discord","telegram","hackernews","producthunt"],"description":"Target platform"},"content_type":{"type":"string","enum":["post","thread","video","article","story","reel","newsletter"],"description":"Content type"},"target_audience":{"type":"string","description":"Target audience description"}},"required":["text","platform"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"hype_find_influencers","description":"Find relevant influencers by platform, niche, and minimum follower count from the tracked influencer database.","parameters":{"type":"object","properties":{"platform":{"type":"string","enum":["twitter","linkedin","reddit","tiktok","youtube","instagram","discord","telegram","hackernews","producthunt"],"description":"Filter by platform"},"niche":{"type":"string","description":"Filter by niche/topic"},"min_followers":{"type":"number","description":"Minimum follower count"},"limit":{"type":"number","description":"Max results (default: 20)"}},"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"hype_rank_influencers","description":"Rank a list of influencers by composite score based on engagement rate, audience quality, relevance, follower count, and post frequency.","parameters":{"type":"object","properties":{"influencers":{"type":"array","items":{"type":"object","properties":{"handle":{"type":"string"},"name":{"type":"string"},"platform":{"type":"string"},"followers":{"type":"number"},"engagementRate":{"type":"number"},"niche":{"type":"array","items":{"type":"string"}},"relevanceScore":{"type":"number"},"audienceQuality":{"type":"number"},"avgLikes":{"type":"number"},"avgComments":{"type":"number"},"postFrequency":{"type":"number"}},"required":["handle","name","platform","followers","engagementRate"],"additionalProperties":false},"description":"Array of influencer profiles to rank"}},"required":["influencers"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"hype_get_best_times","description":"Get best posting times by platform. Returns day-of-week and hour (UTC) with expected engagement scores.","parameters":{"type":"object","properties":{"platform":{"type":"string","enum":["twitter","linkedin","reddit","tiktok","youtube","instagram","discord","telegram","hackernews","producthunt"],"description":"Specific platform (omit for all platforms)"}},"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"hype_get_campaign_report","description":"Generate a comprehensive performance report for a campaign including total engagement, impressions, virality, and recommendations.","parameters":{"type":"object","properties":{"campaign_id":{"type":"string","description":"Campaign ID"}},"required":["campaign_id"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"hype_list_campaigns","description":"List campaigns with optional filters for status and platform.","parameters":{"type":"object","properties":{"status":{"type":"string","enum":["draft","active","paused","completed"],"description":"Filter by campaign status"},"platform":{"type":"string","enum":["twitter","linkedin","reddit","tiktok","youtube","instagram","discord","telegram","hackernews","producthunt"],"description":"Filter by platform"},"limit":{"type":"number","description":"Max results (default: 20)"}},"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"hype_get_trending_topics","description":"Get trending topics by platform with velocity scores, volume, and sentiment data.","parameters":{"type":"object","properties":{"platform":{"type":"string","enum":["twitter","linkedin","reddit","tiktok","youtube","instagram","discord","telegram","hackernews","producthunt"],"description":"Platform to check trends"},"query":{"type":"string","description":"Optional search query to filter topics"}},"required":["platform"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"hype_analyze_competitor","description":"Analyze a competitor''s social media presence. Provides follower counts, engagement rates, content themes, strengths, and weaknesses.","parameters":{"type":"object","properties":{"handle":{"type":"string","description":"Competitor handle/username"},"platform":{"type":"string","enum":["twitter","linkedin","reddit","tiktok","youtube","instagram","discord","telegram","hackernews","producthunt"],"description":"Platform to analyze"}},"required":["handle","platform"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"hype_get_content_calendar","description":"Generate a content calendar with suggested topics, platforms, content types, and posting times for the next 7 days.","parameters":{"type":"object","properties":{"platforms":{"type":"array","items":{"type":"string","enum":["twitter","linkedin","reddit","tiktok","youtube","instagram","discord","telegram","hackernews","producthunt"]},"description":"Target platforms"},"topics":{"type":"array","items":{"type":"string"},"description":"Key topics/themes to cover"},"posts_per_day":{"type":"number","description":"Posts per day (default: 2)"}},"required":["platforms"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"hype_status","description":"System health and statistics: plugin version, configuration status, and connected platforms.","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}}]'::jsonb, 'raijinlabs/lucid-skills', 'first-party', true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, version=EXCLUDED.version, category=EXCLUDED.category, tool_manifest=EXCLUDED.tool_manifest, source_repo=EXCLUDED.source_repo, source=EXCLUDED.source, verified=EXCLUDED.verified;
INSERT INTO plugin_catalog (slug, name, description, version, category, tool_manifest, source_repo, source, verified) VALUES ('lucid-invoice', 'Lucid Invoice', 'Billing and revenue management: invoicing, payments, reporting', '1.0.0', 'finance', '[{"name":"invoice_create_client","description":"Create a new client for invoicing. Provide name, email, optional company, address, tax ID, and payment terms (net days).","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"invoice_create_invoice","description":"Create a new invoice for a client. Provide client_id, line items (description, quantity, unit_price), optional tax_rate, discount, currency, and notes.","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"invoice_send_invoice","description":"Mark an invoice as sent. In production, this would trigger email delivery to the client.","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"invoice_record_payment","description":"Record a payment against an invoice. Provide invoice_id, amount, payment method, and optional reference number.","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"invoice_get_outstanding","description":"Get all outstanding (unpaid) invoices and total amounts. Optionally filter by client_id.","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"invoice_create_subscription","description":"Create a recurring subscription for a client. Provide client_id, plan name, amount, currency, and billing cycle.","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"invoice_get_revenue","description":"Get revenue analytics including MRR, ARR, and growth metrics. Specify period granularity and optional date range.","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"invoice_manage_clients","description":"Manage clients: list all, get by ID, or update client details. Actions: list, get, update.","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"invoice_get_aging_report","description":"Generate an accounts receivable aging report showing outstanding invoices bucketed by current, 1-30, 31-60, 61-90, and 90+ days.","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"invoice_forecast_revenue","description":"Forecast revenue for the next N months based on current subscriptions and optional monthly growth rate (%).","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"invoice_status","description":"Check Lucid Invoice system health and configuration status.","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}}]'::jsonb, 'raijinlabs/lucid-skills', 'first-party', true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, version=EXCLUDED.version, category=EXCLUDED.category, tool_manifest=EXCLUDED.tool_manifest, source_repo=EXCLUDED.source_repo, source=EXCLUDED.source, verified=EXCLUDED.verified;
INSERT INTO plugin_catalog (slug, name, description, version, category, tool_manifest, source_repo, source, verified) VALUES ('lucid-meet', 'Lucid Meet', 'Meeting intelligence: transcription, action items, calendar integration', '1.0.0', 'productivity', '[{"name":"meet_analyze_transcript","description":"Analyze a meeting transcript to extract key topics, decisions, action items, and sentiment. Provide either a meeting_id (to analyze stored transcript) or raw transcript text.","parameters":{"type":"object","properties":{"meeting_id":{"type":"number","description":"ID of the meeting whose transcript to analyze"},"transcript":{"type":"string","description":"Raw transcript text to analyze (used if meeting_id not provided)"}},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"meet_extract_action_items","description":"Extract action items from a meeting transcript with assignees, deadlines, and priority levels. Optionally saves them to the database.","parameters":{"type":"object","properties":{"meeting_id":{"type":"number","description":"Meeting ID whose transcript to parse"},"transcript":{"type":"string","description":"Raw transcript text (used if meeting_id not provided)"},"save":{"type":"boolean","description":"Whether to save extracted items to the database (default: false)"}},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"meet_create_summary","description":"Generate a structured meeting summary including key topics, decisions, action items, attendees, and sentiment.","parameters":{"type":"object","properties":{"meeting_id":{"type":"number","description":"ID of the meeting to summarize"}},"required":["meeting_id"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"meet_track_followup","description":"Track follow-up items and their completion status. Create new follow-ups, list pending ones, or mark them complete.","parameters":{"type":"object","properties":{"action":{"type":"string","enum":["create","list","complete"],"description":"Action to perform: create, list, or complete a follow-up"},"follow_up_id":{"type":"number","description":"Follow-up ID (required for complete action)"},"meeting_id":{"type":"number","description":"Filter by meeting ID (for list action)"},"recipient":{"type":"string","description":"Recipient name/email (required for create action)"},"message":{"type":"string","description":"Follow-up message (required for create action)"},"scheduled_for":{"type":"string","description":"ISO date for when to send follow-up (for create action)"}},"required":["action"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"meet_list_meetings","description":"List meetings with optional filters by type, status, date range. Returns a formatted list of meetings.","parameters":{"type":"object","properties":{"type":{"type":"string","enum":["standup","planning","review","one_on_one","all_hands","client","interview","brainstorm","custom"],"description":"Filter by meeting type"},"status":{"type":"string","enum":["scheduled","in_progress","completed","cancelled"],"description":"Filter by meeting status"},"since":{"type":"string","description":"Filter meetings scheduled after this ISO date"},"limit":{"type":"number","minimum":1,"maximum":100,"description":"Maximum number of meetings to return (default: 20)"}},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"meet_search_meetings","description":"Search across meeting transcripts, summaries, and titles for a keyword or phrase. Returns matching meetings with context snippets.","parameters":{"type":"object","properties":{"query":{"type":"string","description":"Search query to match against meeting content"},"limit":{"type":"number","minimum":1,"maximum":50,"description":"Maximum number of results (default: 10)"}},"required":["query"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"meet_get_participant_stats","description":"Get speaking time and contribution metrics per participant in a meeting. Analyzes transcript for line count, word count, and assigned action items.","parameters":{"type":"object","properties":{"meeting_id":{"type":"number","description":"Meeting ID to analyze participant stats for"}},"required":["meeting_id"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"meet_detect_sentiment","description":"Analyze the sentiment of a meeting, both overall and per section/topic. Identifies positive, negative, neutral, and mixed tones.","parameters":{"type":"object","properties":{"meeting_id":{"type":"number","description":"Meeting ID to analyze"},"transcript":{"type":"string","description":"Raw transcript text (used if meeting_id not provided)"}},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"meet_generate_agenda","description":"Generate a meeting agenda based on meeting type, participants, and context from previous meetings and pending action items.","parameters":{"type":"object","properties":{"type":{"type":"string","enum":["standup","planning","review","one_on_one","all_hands","client","interview","brainstorm","custom"],"description":"Type of meeting to generate agenda for"},"participants":{"type":"array","items":{"type":"string"},"description":"List of participant names"},"include_carryover":{"type":"boolean","description":"Include pending action items from recent meetings (default: true)"}},"required":["type"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"meet_create_meeting","description":"Create a new meeting entry in the system. Provide title, type, date, attendees, and optionally transcript/recording URL.","parameters":{"type":"object","properties":{"title":{"type":"string","description":"Meeting title"},"type":{"type":"string","enum":["standup","planning","review","one_on_one","all_hands","client","interview","brainstorm","custom"],"description":"Type of meeting"},"scheduled_at":{"type":"string","description":"ISO date when the meeting is scheduled (defaults to now)"},"status":{"type":"string","enum":["scheduled","in_progress","completed","cancelled"],"description":"Meeting status (default: scheduled)"},"attendees":{"type":"array","items":{"type":"string"},"description":"List of attendee names"},"transcript":{"type":"string","description":"Meeting transcript text"},"recording_url":{"type":"string","description":"URL to meeting recording"},"duration_minutes":{"type":"number","description":"Duration in minutes"}},"required":["title","type"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"meet_get_insights","description":"Get meeting insights including patterns, frequency, productivity metrics, action item completion rates, and bottleneck analysis.","parameters":{"type":"object","properties":{"days":{"type":"number","minimum":1,"maximum":365,"description":"Number of days to analyze (default: 30)"}},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"meet_status","description":"System health and statistics: meeting count, action items, follow-ups, provider status, and configuration info.","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}}]'::jsonb, 'raijinlabs/lucid-skills', 'first-party', true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, version=EXCLUDED.version, category=EXCLUDED.category, tool_manifest=EXCLUDED.tool_manifest, source_repo=EXCLUDED.source_repo, source=EXCLUDED.source, verified=EXCLUDED.verified;
INSERT INTO plugin_catalog (slug, name, description, version, category, tool_manifest, source_repo, source, verified) VALUES ('lucid-metrics', 'Lucid Metrics', 'Product analytics: KPIs, dashboards, trend detection, reporting', '1.0.0', 'analytics', '[{"name":"metrics_track_event","description":"Track a product analytics event. Ingests events like page views, clicks, purchases, signups, and custom events into the analytics database.","parameters":{"type":"object","properties":{"event_name":{"type":"string","description":"Name of the event (e.g. \"button_click\", \"purchase\")"},"user_id":{"type":"string","description":"User ID associated with the event"},"properties":{"type":"object","propertyNames":{"type":"string"},"additionalProperties":{},"description":"Additional event properties (key-value pairs)"},"event_type":{"type":"string","enum":["page_view","click","form_submit","purchase","signup","custom"],"description":"Type of event"}},"required":["event_name"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"metrics_query_metric","description":"Query a product metric by name. Returns time series data, aggregated value, and growth rate. Queries configured analytics providers or local database.","parameters":{"type":"object","properties":{"metric_name":{"type":"string","description":"Name of the metric to query"},"period":{"type":"string","enum":["hour","day","week","month","quarter","year"],"description":"Time period granularity for the time series"},"start_date":{"type":"string","description":"Start date (ISO format, e.g. 2024-01-01)"},"end_date":{"type":"string","description":"End date (ISO format)"},"aggregation":{"type":"string","enum":["count","sum","avg","min","max","unique","p50","p90","p99"],"description":"Aggregation type override"}},"required":["metric_name"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"metrics_analyze_funnel","description":"Analyze a conversion funnel. Shows step-by-step conversion rates, drop-off rates, and identifies the bottleneck step. Can use saved funnels or ad-hoc step definitions.","parameters":{"type":"object","properties":{"funnel_name":{"type":"string","description":"Name of a saved funnel definition to analyze"},"steps":{"type":"array","items":{"type":"object","properties":{"event_name":{"type":"string","description":"Event name for this step"},"filters":{"type":"object","propertyNames":{"type":"string"},"additionalProperties":{},"description":"Optional filters"}},"required":["event_name"]},"description":"Ad-hoc funnel steps (array of {event_name, filters?})"},"conversion_window":{"type":"number","description":"Conversion window in hours (default 72)"},"start_date":{"type":"string","description":"Start date (ISO format)"},"end_date":{"type":"string","description":"End date (ISO format)"}},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"metrics_get_retention","description":"Get retention cohort analysis. Shows how well users are retained over time after a specific entry event, with churn point identification.","parameters":{"type":"object","properties":{"entry_event":{"type":"string","description":"The event that defines cohort entry (e.g. \"signup\")"},"return_event":{"type":"string","description":"The event that defines a return (defaults to any event)"},"period":{"type":"string","enum":["hour","day","week","month","quarter","year"],"description":"Cohort period granularity"},"cohort_count":{"type":"number","minimum":1,"maximum":52,"description":"Number of cohorts to analyze (default 8)"}},"required":["entry_event"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"metrics_get_active_users","description":"Get active user counts (DAU, WAU, or MAU) with growth rates compared to the previous period.","parameters":{"type":"object","properties":{"period":{"type":"string","enum":["day","week","month"],"description":"Period for active user calculation"},"start_date":{"type":"string","description":"Start date (ISO format)"},"end_date":{"type":"string","description":"End date (ISO format)"}},"required":["period"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"metrics_analyze_experiment","description":"Analyze an A/B test experiment. Performs statistical significance testing, determines winner, and provides confidence intervals and lift metrics.","parameters":{"type":"object","properties":{"experiment_id":{"type":"string","description":"Experiment ID to analyze"},"experiment_name":{"type":"string","description":"Experiment name to look up"}},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"metrics_track_feature","description":"Create or update a feature for adoption tracking. Set feature status and description to monitor feature lifecycle.","parameters":{"type":"object","properties":{"feature_name":{"type":"string","description":"Name of the feature to track"},"status":{"type":"string","enum":["planned","in_development","beta","ga","deprecated"],"description":"Feature lifecycle status"},"description":{"type":"string","description":"Feature description"}},"required":["feature_name"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"metrics_get_feature_adoption","description":"Get feature adoption metrics including adoption rate, unique users, and time-to-adopt analysis for a specific feature.","parameters":{"type":"object","properties":{"feature_name":{"type":"string","description":"Name of the feature to analyze"},"period":{"type":"string","enum":["hour","day","week","month","quarter","year"],"description":"Analysis period"}},"required":["feature_name"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"metrics_create_dashboard","description":"Create or replace a dashboard with multiple widgets. Each widget can be a line chart, bar chart, pie chart, funnel, cohort, or heatmap.","parameters":{"type":"object","properties":{"name":{"type":"string","description":"Dashboard name"},"widgets":{"type":"array","items":{"type":"object","properties":{"type":{"type":"string","enum":["line","bar","pie","funnel","cohort","heatmap"],"description":"Widget chart type"},"metric":{"type":"string","description":"Metric name for this widget"},"config":{"type":"object","propertyNames":{"type":"string"},"additionalProperties":{},"description":"Widget-specific configuration"}},"required":["type"]},"description":"Array of widget definitions"}},"required":["name","widgets"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"metrics_get_insights","description":"Get AI-ready product analytics insights. Analyzes trends, anomalies, and provides actionable recommendations for the specified period.","parameters":{"type":"object","properties":{"period":{"type":"string","enum":["hour","day","week","month","quarter","year"],"description":"Analysis period"},"focus":{"type":"string","description":"Specific area to focus on (e.g. \"onboarding\", \"purchases\", \"engagement\")"}},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"metrics_compare_periods","description":"Compare a metric across two time periods. Shows values, growth rates, and highlights changes between period A and period B.","parameters":{"type":"object","properties":{"metric_name":{"type":"string","description":"Name of the metric to compare"},"period_a_start":{"type":"string","description":"Period A start date (ISO format)"},"period_a_end":{"type":"string","description":"Period A end date (ISO format)"},"period_b_start":{"type":"string","description":"Period B start date (ISO format)"},"period_b_end":{"type":"string","description":"Period B end date (ISO format)"}},"required":["metric_name","period_a_start","period_a_end","period_b_start","period_b_end"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"metrics_status","description":"System health and statistics: event count, metric definitions, provider status, and configuration overview.","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}}]'::jsonb, 'raijinlabs/lucid-skills', 'first-party', true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, version=EXCLUDED.version, category=EXCLUDED.category, tool_manifest=EXCLUDED.tool_manifest, source_repo=EXCLUDED.source_repo, source=EXCLUDED.source, verified=EXCLUDED.verified;
